import{Frame}from"../primitives/Frame.js";import{define}from"../tools/define.js";class Rings extends Frame{render(band,interval,ratio){this.shadowRoot.innerHTML=`\n      <style>\n        :host {\n          container-type: size;\n          aspect-ratio: ${ratio};\n          display: flex !important;\n          justify-content: center;\n          align-items: center;\n          gap: 1cqw;\n        }\n\n        svg {\n          overflow: visible;\n          aspect-ratio: 1 / 1;\n          max-inline-size: 100cqw;\n          max-block-size: 100cqh;\n          fill: none;\n          stroke: currentColor;\n        }\n\n        circle {\n          fill: ${this.fill?"currentColor":"none"};\n          transform-origin: center;\n          transform: scale(0);\n          transition: transform ${interval} linear;\n        }\n\n        :host([data-playing]) circle {\n          mix-blend-mode: difference;\n          transform: scale(${band});\n        }\n      </style>\n      <svg viewBox="0 0 100 100">\n        ${this.renderItems()}\n      </svg>\n    `}renderItem(i){return`\n      <circle cx="50" cy="50" r="50" style="${this.declaration(i)}"></circle>\n    `}get fill(){return this.hasAttribute("fill")}set fill(value){this.toBoolean("fill",value)}static{define(this)}}export{Rings};